arguments.command:
cd /tmp && mkdir -p stackalloc-test && cd stackalloc-test && dotnet new console --force -q && cat > Program.cs << 'EOF'
using System;

Span<nint> a = stackalloc nint[4];
for (int i = 0; i < a.Length; i++) a[i] = (nint)(i * 10);

Span<nuint> b = stackalloc nuint[4];
for (int i = 0; i < b.Length; i++) b[i] = (nuint)(i * 100);

Console.WriteLine($"Span<nint>:  [{string.Join(", ", a.ToArray())}]");
Console.WriteLine($"Span<nuint>: [{string.Join(", ", b.ToArray())}]");
Console.WriteLine($"nint size:   {sizeof(nint)} bytes");
EOF
dotnet run

